/**
 * LCARdS Object Editor
 *
 * Generic object property editor that solves the "padding problem" and other
 * object-based configurations. Renders N properties in a grid layout with
 * consistent controls.
 *
 * Supports two modes:
 * 1. **Auto-generated**: Provide properties array and controlType/config
 * 2. **Slotted**: Manually provide controls via slots for mixed types
 *
 * Features:
 * - Renders properties in responsive grid (1-4 columns)
 * - Auto-generates labels from property names (snake_case → Title Case)
 * - Supports number, text, boolean, select control types
 * - Passes controlConfig to underlying controls
 * - Reusable for padding, margin, border widths, font configs, etc.
 *
 * @example Auto-generated mode (padding)
 * <lcards-object-editor
 *   .editor=${this}
 *   path="style.padding"
 *   .properties=${['top', 'right', 'bottom', 'left']}
 *   controlType="number"
 *   .controlConfig=${{ min: 0, max: 100 }}
 *   columns="2">
 * </lcards-object-editor>
 *
 * @example Slotted mode (mixed controls)
 * <lcards-object-editor columns="2">
 *   <lcards-form-field path="font.size" label="Size"></lcards-form-field>
 *   <lcards-form-field path="font.weight" label="Weight"></lcards-form-field>
 * </lcards-object-editor>
 */

import { LitElement, html, css } from 'lit';
import './lcards-form-field.js';

export class LCARdSObjectEditor extends LitElement {

    static get properties() {
        return {
            editor: { type: Object },          // Parent editor reference
            path: { type: String },            // Base config path (e.g., 'style.padding')
            properties: { type: Array },       // Array of property names (e.g., ['top', 'right', 'bottom', 'left'])
            controlType: { type: String },     // Control type: 'number', 'text', 'boolean', 'select'
            controlConfig: { type: Object },   // Config passed to controls (min, max, options, etc.)
            columns: { type: Number },         // Number of grid columns (1-4)
            gap: { type: String },             // Grid gap (default: '8px')
            disabled: { type: Boolean }        // Disabled state
        };
    }

    constructor() {
        super();
        this.editor = null;
        this.path = '';
        this.properties = [];
        this.controlType = 'number';
        this.controlConfig = {};
        this.columns = 2;
        this.gap = '8px';
        this.disabled = false;
    }

    static get styles() {
        return css`
            :host {
                display: block;
            }

            .object-editor {
                display: grid;
                gap: var(--grid-gap, 8px);
            }

            .object-editor.cols-1 {
                grid-template-columns: 1fr;
            }

            .object-editor.cols-2 {
                grid-template-columns: 1fr 1fr;
            }

            .object-editor.cols-3 {
                grid-template-columns: 1fr 1fr 1fr;
            }

            .object-editor.cols-4 {
                grid-template-columns: 1fr 1fr 1fr 1fr;
            }

            @media (max-width: 768px) {
                .object-editor.cols-2,
                .object-editor.cols-3,
                .object-editor.cols-4 {
                    grid-template-columns: 1fr;
                }
            }

            @media (min-width: 769px) and (max-width: 1024px) {
                .object-editor.cols-3,
                .object-editor.cols-4 {
                    grid-template-columns: 1fr 1fr;
                }
            }

            .property-field {
                display: flex;
                flex-direction: column;
                gap: 4px;
            }

            .property-label {
                font-size: 12px;
                font-weight: 500;
                color: var(--secondary-text-color, #727272);
                padding: 0 8px;
            }

            .property-control {
                padding: 2px 8px;
            }

            ha-selector {
                width: 100%;
            }
        `;
    }

    render() {
        // Check if using slotted mode
        const hasSlot = this.querySelector('[slot]') || this.children.length > 0;

        if (hasSlot) {
            return this._renderSlottedMode();
        }

        return this._renderAutoGeneratedMode();
    }

    /**
     * Render auto-generated mode
     * @returns {TemplateResult}
     * @private
     */
    _renderAutoGeneratedMode() {
        if (!this.editor || !this.path || !this.properties.length) {
            return html`
                <ha-alert alert-type="error">
                    Object editor requires 'editor', 'path', and 'properties'
                </ha-alert>
            `;
        }

        return html`
            <div 
                class="object-editor cols-${this.columns}"
                style="--grid-gap: ${this.gap}">
                ${this.properties.map(prop => this._renderProperty(prop))}
            </div>
        `;
    }

    /**
     * Render slotted mode
     * @returns {TemplateResult}
     * @private
     */
    _renderSlottedMode() {
        return html`
            <div 
                class="object-editor cols-${this.columns}"
                style="--grid-gap: ${this.gap}">
                <slot></slot>
            </div>
        `;
    }

    /**
     * Render a single property field
     * @param {string} property - Property name
     * @returns {TemplateResult}
     * @private
     */
    _renderProperty(property) {
        const propertyPath = `${this.path}.${property}`;
        const label = this._formatPropertyLabel(property);
        const value = this.editor._getConfigValue(propertyPath);

        return html`
            <div class="property-field">
                <div class="property-label">${label}</div>
                <div class="property-control">
                    ${this._renderControl(propertyPath, value)}
                </div>
            </div>
        `;
    }

    /**
     * Render control based on controlType
     * @param {string} path - Config path
     * @param {*} value - Current value
     * @returns {TemplateResult}
     * @private
     */
    _renderControl(path, value) {
        switch (this.controlType) {
            case 'number':
                return this._renderNumberControl(path, value);
            case 'text':
                return this._renderTextControl(path, value);
            case 'boolean':
                return this._renderBooleanControl(path, value);
            case 'select':
                return this._renderSelectControl(path, value);
            default:
                return this._renderTextControl(path, value);
        }
    }

    /**
     * Render number control (slider + number input)
     * @param {string} path - Config path
     * @param {*} value - Current value
     * @returns {TemplateResult}
     * @private
     */
    _renderNumberControl(path, value) {
        const config = {
            mode: 'box',
            ...this.controlConfig
        };

        return html`
            <ha-selector
                .hass=${this.editor?.hass}
                .selector=${{ number: config }}
                .value=${value ?? config.min ?? 0}
                .disabled=${this.disabled}
                @value-changed=${(e) => this._handleValueChange(path, e)}>
            </ha-selector>
        `;
    }

    /**
     * Render text control
     * @param {string} path - Config path
     * @param {*} value - Current value
     * @returns {TemplateResult}
     * @private
     */
    _renderTextControl(path, value) {
        return html`
            <ha-selector
                .hass=${this.editor?.hass}
                .selector=${{ text: this.controlConfig }}
                .value=${value || ''}
                .disabled=${this.disabled}
                @value-changed=${(e) => this._handleValueChange(path, e)}>
            </ha-selector>
        `;
    }

    /**
     * Render boolean control (switch)
     * @param {string} path - Config path
     * @param {*} value - Current value
     * @returns {TemplateResult}
     * @private
     */
    _renderBooleanControl(path, value) {
        return html`
            <ha-selector
                .hass=${this.editor?.hass}
                .selector=${{ boolean: {} }}
                .value=${value ?? false}
                .disabled=${this.disabled}
                @value-changed=${(e) => this._handleValueChange(path, e)}>
            </ha-selector>
        `;
    }

    /**
     * Render select control (dropdown)
     * @param {string} path - Config path
     * @param {*} value - Current value
     * @returns {TemplateResult}
     * @private
     */
    _renderSelectControl(path, value) {
        const config = {
            mode: 'dropdown',
            ...this.controlConfig
        };

        return html`
            <ha-selector
                .hass=${this.editor?.hass}
                .selector=${{ select: config }}
                .value=${value || ''}
                .disabled=${this.disabled}
                @value-changed=${(e) => this._handleValueChange(path, e)}>
            </ha-selector>
        `;
    }

    /**
     * Handle value change from control
     * @param {string} path - Config path
     * @param {CustomEvent} event - value-changed event
     * @private
     */
    _handleValueChange(path, event) {
        if (this.disabled) return;

        const newValue = event.detail.value;
        this.editor._setConfigValue(path, newValue);
        
        // Emit event for parent components
        this.dispatchEvent(new CustomEvent('property-changed', {
            detail: { path, value: newValue },
            bubbles: true,
            composed: true
        }));
    }

    /**
     * Format property name as readable label
     * @param {string} property - Property name (e.g., 'top', 'font_size')
     * @returns {string} Formatted label (e.g., 'Top', 'Font Size')
     * @private
     */
    _formatPropertyLabel(property) {
        return property
            .split(/[-_]/)
            .map(word => word.charAt(0).toUpperCase() + word.slice(1))
            .join(' ');
    }
}

customElements.define('lcards-object-editor', LCARdSObjectEditor);
